		'Enter your Intercom access token. You can generate one in the Developer Hub in your Intercom account <a href="https://app.intercom.com/developers/_" target="_blank">here</a>.' => 'Geben Sie Ihr Intercom-Zugriffstoken ein. Sie können eines im Developer Hub in Ihrem Intercom-Konto <a href="https://app.intercom.com/developers/_" target="_blank">hier</a> generieren.',
		'Enter the API Key for your Kartra account. You can find your key under <a href="https://app.kartra.com/integrations/api/key" target="_blank">the My Integrations menu</a>.' => 'Geben Sie den API-Schlüssel für Ihr Kartra-Konto ein. Sie finden Ihren Schlüssel im <a href="https://app.kartra.com/integrations/api/key" target="_blank">Menü Meine Integrationen</a>.',
		'API Password'                                     => 'API-Passwort',
